"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Stepper root context ─────────────────────────────────────────────────────

interface StepperContextValue {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper(): StepperContextValue {
  const ctx = React.useContext(StepperContext)
  if (!ctx) {
    throw new Error("useStepper must be used within a <Stepper>")
  }
  return ctx
}

// ─── StepperItem context ──────────────────────────────────────────────────────

interface StepperItemContextValue {
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem(): StepperItemContextValue {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx) {
    throw new Error("useStepperItem must be used within a <StepperItem>")
  }
  return ctx
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

interface StepperProps extends React.ComponentProps<"div"> {
  /** Zero-based index of the initially active step (uncontrolled). */
  defaultValue?: number
  /** Controlled active step index. */
  value?: number
  /** Callback fired when the active step changes. */
  onValueChange?: (step: number) => void
  /** Layout direction of the step list. @default "horizontal" */
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  className,
  defaultValue = 0,
  value,
  onValueChange,
  orientation = "horizontal",
  ...props
}: StepperProps) {
  const [internalStep, setInternalStep] = React.useState(defaultValue)
  const isControlled = value !== undefined
  const activeStep = isControlled ? value! : internalStep

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (!isControlled) setInternalStep(step)
      onValueChange?.(step)
    },
    [isControlled, onValueChange]
  )

  const ctx = React.useMemo<StepperContextValue>(
    () => ({ activeStep, setActiveStep, orientation }),
    [activeStep, setActiveStep, orientation]
  )

  return (
    <StepperContext.Provider value={ctx}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** Zero-based index that identifies this step. */
  step: number
  /** Manually override the completed state for this step. */
  completed?: boolean
  /** Prevent the user from navigating to this step. */
  disabled?: boolean
}

function StepperItem({
  className,
  step,
  completed,
  disabled = false,
  ...props
}: StepperItemProps) {
  const { activeStep, orientation } = useStepper()

  const isActive = activeStep === step
  const isCompleted =
    completed !== undefined ? completed : activeStep > step
  const state = isActive ? "active" : isCompleted ? "completed" : "inactive"

  const ctx = React.useMemo<StepperItemContextValue>(
    () => ({ step, isActive, isCompleted, isDisabled: disabled }),
    [step, isActive, isCompleted, disabled]
  )

  return (
    <StepperItemContext.Provider value={ctx}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-disabled={disabled ? "" : undefined}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-1 flex-row items-center"
            : "flex-col",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepper()
  const { step, isActive, isCompleted, isDisabled } = useStepperItem()
  const state = isActive ? "active" : isCompleted ? "completed" : "inactive"

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      disabled={isDisabled}
      onClick={() => setActiveStep(step)}
      className={cn(
        "flex shrink-0 items-center gap-3 rounded-md text-sm outline-none transition-all",
        "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {/* Step indicator circle */}
      <span
        aria-hidden="true"
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-xs font-semibold transition-colors",
          isActive || isCompleted
            ? "border-primary bg-primary text-primary-foreground"
            : "border-muted-foreground/40 bg-background text-muted-foreground"
        )}
      >
        {isCompleted ? <CheckIcon className="size-4" /> : step + 1}
      </span>

      {/* Label slot — wraps StepperTitle / StepperDescription */}
      {children && (
        <span className="flex flex-col gap-0.5 text-left">{children}</span>
      )}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { isActive, isCompleted } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      className={cn(
        "text-sm font-medium leading-none transition-colors",
        isActive || isCompleted ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────
// Render this as the last child of a <StepperItem> (except the final item).
// It reads completion state from the enclosing <StepperItem> automatically.

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { isCompleted } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-state={isCompleted ? "completed" : "pending"}
      aria-hidden="true"
      className={cn(
        "shrink-0 rounded-full transition-colors",
        "data-[state=completed]:bg-primary data-[state=pending]:bg-border",
        orientation === "horizontal"
          ? "mx-2 h-0.5 min-w-8 flex-1"
          : "ms-[15px] mt-1 h-8 w-0.5",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────
// Must be rendered inside a <Stepper> (anywhere in its subtree).
// Renders its children only when `step` matches the active step.

interface StepperContentProps extends React.ComponentProps<"div"> {
  /** The step index whose content this panel belongs to. */
  step: number
}

function StepperContent({ step, className, ...props }: StepperContentProps) {
  const { activeStep } = useStepper()

  if (activeStep !== step) return null

  return (
    <div
