"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    title: "Account",
    description: "Create your account",
    content:
      "Enter your email address and choose a secure password to create your account.",
  },
  {
    title: "Profile",
    description: "Set up your profile",
    content:
      "Add your name, bio, and a profile picture so others can get to know you.",
  },
  {
    title: "Review",
    description: "Confirm your details",
    content:
      "Review your information carefully, then submit to complete your setup.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  const isFirst = activeStep === 0
  const isLast = activeStep === steps.length - 1

  return (
    // Stepper wraps both the indicator row and the content panels so that
    // StepperContent can read the active step from context.
    <Stepper
      value={activeStep}
      onValueChange={setActiveStep}
      className="w-full max-w-lg flex-col gap-6"
    >
      {/* ── Indicator row ── */}
      <div className="flex w-full flex-row items-start">
        {steps.map((step, index) => (
          <StepperItem key={step.title} step={index}>
            <StepperTrigger>
              <StepperTitle>{step.title}</StepperTitle>
              <StepperDescription>{step.description}</StepperDescription>
            </StepperTrigger>
            {index < steps.length - 1 && <StepperSeparator />}
          </StepperItem>
        ))}
      </div>

      {/* ── Step content panels ── */}
      {steps.map((step, index) => (
        <StepperContent key={step.title} step={index} className="mt-0">
          <div className="rounded-lg border bg-card p-4 text-sm text-muted-foreground">
            {step.content}
          </div>
        </StepperContent>
      ))}

      {/* ── Navigation ── */}
      <div className="flex gap-2">
        <Button
          variant="outline"
          size="sm"
          disabled={isFirst}
          onClick={() => setActiveStep((s) => s - 1)}
        >
          Back
        </Button>
        <Button
          size="sm"
          disabled={isLast}
          onClick={() => setActiveStep((s) => s + 1)}
        >
          {activeStep === steps.length - 2 ? "Review" : "Next"}
        </Button>
      </div>
    </Stepper>
  )
}

